@page "/apply"
@rendermode InteractiveServer
@using sv_ca1c84971f034fb98514b10e44be6be1.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @* Step Indicator Bar *@
    <nav class="mb-4">
        <div class="d-flex justify-content-between position-relative">
            @* Connecting line behind the steps *@
            <div class="position-absolute w-100" style="top: 18px; left: 0; z-index: 0;">
                <div class="w-100 border-top border-2" style="border-color: #dee2e6 !important;"></div>
            </div>
            @for (int i = 0; i < StepNames.Length; i++)
            {
                var stepIndex = i;
                var isCurrent = stepIndex == _currentStep;
                var isCompleted = stepIndex < _currentStep;
                var isFuture = stepIndex > _currentStep;
                <div class="text-center position-relative" style="z-index: 1; flex: 1;">
                    <button class="btn rounded-circle d-inline-flex align-items-center justify-content-center @StepCircleClass(stepIndex)"
                            style="width: 36px; height: 36px; font-size: 0.85rem;"
                            disabled="@(isFuture || _submitted)"
                            @onclick="() => GoToStep(stepIndex)">
                        @if (isCompleted)
                        {
                            <span>✓</span>
                        }
                        else
                        {
                            <span>@(stepIndex + 1)</span>
                        }
                    </button>
                    <div class="small mt-1 @(isCurrent ? "fw-bold" : "") @(isFuture ? "text-muted" : "")">
                        @StepNames[stepIndex]
                    </div>
                </div>
            }
        </div>
    </nav>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger alert-dismissible" role="alert">
            @_errorMessage
            <button type="button" class="btn-close" @onclick="() => _errorMessage = null"></button>
        </div>
    }

    @if (_submitted)
    {
        <div class="text-center py-5">
            <div class="mb-3">
                <span class="badge bg-success rounded-circle d-inline-flex align-items-center justify-content-center" style="width: 64px; height: 64px; font-size: 1.5rem;">✓</span>
            </div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="text-muted">Your application ID is <strong>#@_applicationId</strong></p>
            <p>Thank you for applying. We will review your application and get back to you.</p>
        </div>
    }
    else
    {
        @switch (_currentStep)
        {
            case 0:
                <StepPersonalInfo Personal="_personal" OnChanged="StateHasChanged" />
                break;
            case 1:
                <StepWorkHistory WorkEntries="_workEntries" OnChanged="StateHasChanged" />
                break;
            case 2:
                <StepReferences References="_references" OnChanged="StateHasChanged" />
                break;
            case 3:
                <StepCoverLetter @bind-CoverLetter="_coverLetter" MaxLength="2000" />
                break;
            case 4:
                <StepReview Personal="_personal" WorkEntries="_workEntries"
                            References="_references" CoverLetter="@_coverLetter"
                            OnEditStep="GoToStep" />
                break;
        }

        <div class="d-flex justify-content-between mt-4">
            @if (_currentStep > 0)
            {
                <button class="btn btn-outline-secondary" @onclick="PreviousStep" disabled="@_isProcessing">
                    ← Back
                </button>
            }
            else
            {
                <div></div>
            }

            @if (_currentStep < StepNames.Length - 1)
            {
                <button class="btn btn-primary" @onclick="NextStep" disabled="@_isProcessing">
                    @if (_isProcessing)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Next →
                </button>
            }
            else
            {
                <button class="btn btn-success" @onclick="SubmitApplication" disabled="@_isProcessing">
                    @if (_isProcessing)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Submit Application
                </button>
            }
        </div>
    }
</div>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int _currentStep;
    private bool _isProcessing;
    private bool _submitted;
    private int _applicationId;
    private string? _errorMessage;

    // Step 1 state
    private PersonalInfoModel _personal = new();

    // Step 2 state
    private List<WorkEntryModel> _workEntries = new() { new() };

    // Step 3 state
    private List<ReferenceModel> _references = new() { new(), new() };

    // Step 4 state
    private string _coverLetter = "";

    private string StepCircleClass(int step)
    {
        if (step == _currentStep) return "btn-primary";
        if (step < _currentStep) return "btn-success";
        return "btn-outline-secondary";
    }

    private void GoToStep(int step)
    {
        if (step < _currentStep && !_submitted)
        {
            _errorMessage = null;
            _currentStep = step;
        }
    }

    private async Task NextStep()
    {
        _errorMessage = null;
        _isProcessing = true;

        try
        {
            if (!await ValidateCurrentStep()) return;
            _currentStep++;
        }
        finally
        {
            _isProcessing = false;
        }
    }

    private void PreviousStep()
    {
        _errorMessage = null;
        if (_currentStep > 0) _currentStep--;
    }

    private async Task<bool> ValidateCurrentStep()
    {
        switch (_currentStep)
        {
            case 0:
                if (string.IsNullOrWhiteSpace(_personal.FullName))
                    { _errorMessage = "Full name is required."; return false; }
                if (string.IsNullOrWhiteSpace(_personal.Email))
                    { _errorMessage = "Email is required."; return false; }
                if (string.IsNullOrWhiteSpace(_personal.Phone))
                    { _errorMessage = "Phone is required."; return false; }
                if (string.IsNullOrWhiteSpace(_personal.Address))
                    { _errorMessage = "Address is required."; return false; }
                if (!await ApplicationService.ValidateEmailAsync(_personal.Email))
                    { _errorMessage = "Please enter a valid email address."; return false; }
                return true;

            case 1:
                foreach (var entry in _workEntries)
                {
                    if (string.IsNullOrWhiteSpace(entry.Company))
                        { _errorMessage = "Company name is required for all work entries."; return false; }
                    if (string.IsNullOrWhiteSpace(entry.Title))
                        { _errorMessage = "Job title is required for all work entries."; return false; }
                    if (entry.StartDate == default)
                        { _errorMessage = "Start date is required for all work entries."; return false; }
                }
                return true;

            case 2:
                if (_references.Count < 2)
                    { _errorMessage = "At least 2 references are required."; return false; }
                foreach (var r in _references)
                {
                    if (string.IsNullOrWhiteSpace(r.Name))
                        { _errorMessage = "Name is required for all references."; return false; }
                    if (string.IsNullOrWhiteSpace(r.Relationship))
                        { _errorMessage = "Relationship is required for all references."; return false; }
                    if (string.IsNullOrWhiteSpace(r.Email))
                        { _errorMessage = "Email is required for all references."; return false; }
                    if (string.IsNullOrWhiteSpace(r.Phone))
                        { _errorMessage = "Phone is required for all references."; return false; }
                }
                return true;

            case 3:
                if (string.IsNullOrWhiteSpace(_coverLetter))
                    { _errorMessage = "Cover letter is required."; return false; }
                return true;

            default:
                return true;
        }
    }

    private async Task SubmitApplication()
    {
        _errorMessage = null;
        _isProcessing = true;

        try
        {
            var personal = new PersonalInfo(_personal.FullName, _personal.Email, _personal.Phone, _personal.Address);
            var workEntries = _workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description ?? "")).ToList();
            var work = new WorkHistory(workEntries);
            var refs = _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();

            var application = new JobApplication(personal, work, refs, _coverLetter);
            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _isProcessing = false;
        }
    }

    // Mutable models for form binding
    public class PersonalInfoModel
    {
        public string FullName { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
        public string Address { get; set; } = "";
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
