@using static sv_ca1c84971f034fb98514b10e44be6be1.Components.Pages.Apply

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name <span class="text-danger">*</span></label>
    <input type="text" class="form-control" @bind="Personal.FullName" @bind:event="oninput"
           @bind:after="NotifyChanged" placeholder="John Doe" />
</div>

<div class="mb-3">
    <label class="form-label">Email <span class="text-danger">*</span></label>
    <input type="email" class="form-control" @bind="Personal.Email" @bind:event="oninput"
           @bind:after="NotifyChanged" placeholder="john@example.com" />
</div>

<div class="mb-3">
    <label class="form-label">Phone <span class="text-danger">*</span></label>
    <input type="tel" class="form-control" @bind="Personal.Phone" @bind:event="oninput"
           @bind:after="NotifyChanged" placeholder="(555) 123-4567" />
</div>

<div class="mb-3">
    <label class="form-label">Address <span class="text-danger">*</span></label>
    <textarea class="form-control" rows="2" @bind="Personal.Address" @bind:event="oninput"
              @bind:after="NotifyChanged" placeholder="123 Main St, City, State ZIP"></textarea>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter] public EventCallback OnChanged { get; set; }

    private async Task NotifyChanged() => await OnChanged.InvokeAsync();
}

@using static sv_ca1c84971f034fb98514b10e44be6be1.Components.Pages.Apply

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < WorkEntries.Count; i++)
{
    var index = i;
    var entry = WorkEntries[index];
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Position @(index + 1)</h6>
                @if (WorkEntries.Count > 1)
                {
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="mb-2">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="entry.Company" @bind:event="oninput"
                       @bind:after="NotifyChanged" />
            </div>

            <div class="mb-2">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="entry.Title" @bind:event="oninput"
                       @bind:after="NotifyChanged" />
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" @bind="entry.StartDate"
                           @bind:after="NotifyChanged" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" @bind="entry.EndDate"
                           @bind:after="NotifyChanged" disabled="@entry.IsCurrent" />
                    <div class="form-check mt-1">
                        <input class="form-check-input" type="checkbox" @bind="entry.IsCurrent"
                               @bind:after="NotifyChanged" id="@($"current-{index}")" />
                        <label class="form-check-label" for="@($"current-{index}")">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2" @bind="entry.Description" @bind:event="oninput"
                          @bind:after="NotifyChanged"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-primary" @onclick="AddEntry">
    + Add Another Position
</button>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter] public EventCallback OnChanged { get; set; }

    private async Task AddEntry()
    {
        WorkEntries.Add(new WorkEntryModel());
        await OnChanged.InvokeAsync();
    }

    private async Task RemoveEntry(int index)
    {
        WorkEntries.RemoveAt(index);
        await OnChanged.InvokeAsync();
    }

    private async Task NotifyChanged() => await OnChanged.InvokeAsync();
}

@using static sv_ca1c84971f034fb98514b10e44be6be1.Components.Pages.Apply

<h4 class="mb-3">References</h4>
<p class="text-muted">Please provide 2–3 professional references.</p>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="reference.Name" @bind:event="oninput"
                           @bind:after="NotifyChanged" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="reference.Relationship" @bind:event="oninput"
                           @bind:after="NotifyChanged" placeholder="e.g., Former Manager" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="reference.Email" @bind:event="oninput"
                           @bind:after="NotifyChanged" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="reference.Phone" @bind:event="oninput"
                           @bind:after="NotifyChanged" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-primary" @onclick="AddReference">
        + Add Reference
    </button>
}

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnChanged { get; set; }

    private async Task AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
            await OnChanged.InvokeAsync();
        }
    }

    private async Task RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
            await OnChanged.InvokeAsync();
        }
    }

    private async Task NotifyChanged() => await OnChanged.InvokeAsync();
}

